다음은 openGraph를 적용해봅시다.

<a
  href="https://nextjs.org/docs/app/api-reference/functions/generate-metadata#opengraph"
  target="_blank"
>
  Next js openGraph
</a>

```javascript title="src/app/layout.js"
import { Inter, Manrope } from "next/font/google";
import "./globals.css";
import { cx } from "@/src/utils";
import Header from "@/src/components/Header";
import Footer from "../components/Footer";
import siteMetadata from "../utils/siteMetadata";

const inter = Inter({
  subsets: ["latin"],
  display: "swap",
  variable: "--font-in",
});
const manrope = Manrope({
  subsets: ["latin"],
  display: "swap",
  variable: "--font-mr",
});

export const metadata = {
  metadataBase: new URL(siteMetadata.siteUrl),
  title: {
    template: `%s | ${siteMetadata.title}`,
    default: siteMetadata.title,
  },
  description: siteMetadata.description,
  openGraph: {
    title: siteMetadata.title,
    description: siteMetadata.description,
    url: siteMetadata.siteUrl,
    siteName: siteMetadata.title,
    images: [siteMetadata.socialBanner],
    locale: "ko-kr",
    type: "website",
  },
};

export default function RootLayout({ children }) {
  return (
    <html lang="en">
      <body
        className={cx(inter.variable, manrope.variable, "font-mr bg-light")}
      >
        <Header />
        {children}
        <Footer />
      </body>
    </html>
  );
}
```

다음으로 robots를 적용합니다.

```javascript title="src/app/layout.js"
import { Inter, Manrope } from "next/font/google";
import "./globals.css";
import { cx } from "@/src/utils";
import Header from "@/src/components/Header";
import Footer from "../components/Footer";
import siteMetadata from "../utils/siteMetadata";

const inter = Inter({
  subsets: ["latin"],
  display: "swap",
  variable: "--font-in",
});
const manrope = Manrope({
  subsets: ["latin"],
  display: "swap",
  variable: "--font-mr",
});

export const metadata = {
  metadataBase: new URL(siteMetadata.siteUrl),
  title: {
    template: `%s | ${siteMetadata.title}`,
    default: siteMetadata.title,
  },
  description: siteMetadata.description,
  openGraph: {
    title: siteMetadata.title,
    description: siteMetadata.description,
    url: siteMetadata.siteUrl,
    siteName: siteMetadata.title,
    images: [siteMetadata.socialBanner],
    locale: "ko-kr",
    type: "website",
  },
  robots: {
    index: true,
    follow: true,
    googleBot: {
      index: true,
      follow: false,
      noimageindex: true,
      "max-video-preview": -1,
      "max-image-preview": "large",
      "max-snippet": -1,
    },
  },
};

export default function RootLayout({ children }) {
  return (
    <html lang="en">
      <body
        className={cx(inter.variable, manrope.variable, "font-mr bg-light")}
      >
        <Header />
        {children}
        <Footer />
      </body>
    </html>
  );
}
```

- metadata 객체 내의 robots는 검색 엔진 로봇(크롤러)이 웹 페이지를 어떻게 처리해야 하는지 지시하는 데 사용됩니다.
- index : 검색 엔진이 이 페이지를 인덱스에 추가할 수 있는지 여부를 나타냅니다. true로 설정되면, 검색 엔진은 이 페이지를 인덱싱하여 검색 결과에 표시할 수 있습니다.
- follow : 이 속성은 페이지 내의 링크를 검색 엔진이 따를 수 있는지 여부를 지정합니다. true로 설정되면, 검색 엔진은 페이지에 있는 모든 링크를 따라갈 수 있습니다.
- googleBot: 이 객체는 구글 검색 엔진 로봇인 Googlebot에 대한 추가적인 지침을 제공합니다.
- max-video-preview : 검색 결과에서 비디오 미리보기의 최대 길이를 지정합니다. -1로 설정하면 미리보기가 허용되지 않습니다.
- max-image-preview: 검색 결과에서 이미지 미리보기의 최대 크기를 지정합니다. 'large'로 설정하면 큰 이미지 미리보기가 허용됩니다.
- max-snippet: 검색 결과에서 표시될 수 있는 페이지의 텍스트 스니펫의 최대 길이를 지정합니다. -1로 설정하면 스니펫이 표시되지 않습니다.

